```go
func BenchmarkHasher(b *testing.B) {
	n := &fullNode{}
	//data := make([]byte, 256)
	hasher := newHasher(false)
	b.Run("hashData", func(b *testing.B) {
		for i := 0; i < b.N; i++ {
			hash := hasher.fullnodeToHash(n, true)
			_ = hash
		}
	})
	b.Run("hashDataTo", func(b *testing.B) {
		for i := 0; i < b.N; i++ {
			hash := hasher.fullnodeToHash(n, true)
			_ = hash
		}
	})
}
